const App: React.FC = () => {
  const [previousSessionTime] = useState(() => localStorage.getItem('lastSessionTime'));

  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(true); 
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string; data?: any } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const [ordersCountSinceBackup, setOrdersCountSinceBackup] = useState(() => Number(localStorage.getItem('backupCounter') || 0));

  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const [loginPassword, setLoginPassword] = useState(() => localStorage.getItem('loginPassword') || '2026');
  const [systemPassword, setSystemPassword] = useState(() => localStorage.getItem('systemPassword') || '@@A2026A@@');

  const [showBackupReminder, setShowBackupReminder] = useState(false);
  const lastBackupTimestamp = useRef<number>(Date.now());

  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  const handleLogout = () => {
    sessionStorage.removeItem('isAuth');
    setIsAuthenticated(false);
  };

  const handleOpenProtected = (target: string, data?: any) => {
    setShowLock({ target, data });
  };

  const completeOrder = useCallback((items: any[], customerName?: string, customerId?: string, saleType: SaleType = 'retail') => {
    const orderId = Date.now().toString();
    const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    const todayDate = new Date().toLocaleDateString('en-US');

    const activeTodaySales = sales.filter(s => s.date === todayDate);
    const activeMax = activeTodaySales.length > 0 
      ? Math.max(...activeTodaySales.map(s => s.customerNumber)) 
      : 0;

    const archivedToday = history.find(h => h.date === todayDate);
    const archivedMax = (archivedToday && archivedToday.items.length > 0)
      ? Math.max(...archivedToday.items.map(s => s.customerNumber))
      : 0;

    const nextCustomerNumber = Math.max(activeMax, archivedMax) + 1;

    const newItems: SaleItem[] = items.map(item => ({
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      orderId,
      customerNumber: nextCustomerNumber,
      customerName,
      customerId,
      saleType,
      time,
      date: todayDate
    }));

    setSales(prev => [...prev, ...newItems]);
    setInvoiceItems(newItems);

    const nextCount = ordersCountSinceBackup + 1;
    setOrdersCountSinceBackup(nextCount);
    if (nextCount >= 40) {
      setShowBackupReminder(true);
    }
  }, [sales, history, ordersCountSinceBackup]);

  const handleUpdateProduct = (id: string, updatedProduct: Partial<Product>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updatedProduct } : p));
  };

  const handleUpdateArchivedOrder = (dayId: string, orderId: string, updatedItems: SaleItem[], newCustomerName?: string) => {
    setHistory(prev => prev.map(day => {
      if (day.id === dayId) {
        const otherItems = day.items.filter(item => item.orderId !== orderId);
        const finalItems = [...otherItems, ...updatedItems.map(it => ({ ...it, customerName: newCustomerName || it.customerName }))];
        return {
          ...day,
          items: finalItems,
          totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalItems: finalItems.length
        };
      }
      return day;
    }));
  };

  const handleDeleteArchivedOrder = (dayId: string, orderId: string) => {
    setHistory(prev => {
      const updated = prev.map(day => {
        if (day.id === dayId) {
          const finalItems = day.items.filter(item => item.orderId !== orderId);
          return {
            ...day,
            items: finalItems,
            totalRevenue: finalItems.reduce((s, i) => s + (i.price * i.quantity), 0),
            totalItems: finalItems.length
          };
        }
        return day;
      });
      return updated.filter(day => day.items.length > 0 || (day.purchaseInvoices && day.purchaseInvoices.length > 0));
    });
  };

  const handleDeleteArchivedDay = (dayId: string) => {
    setHistory(prev => prev.filter(day => day.id !== dayId));
  };

  const handleLoginSuccess = () => {
    sessionStorage.setItem('isAuth', 'true');
    setIsAuthenticated(true);
  };

  const finalizeWelcome = () => {
    setIsInitializing(false);
  };

  useEffect(() => {
    const now = new Date();
    const formattedDate = now.toLocaleDateString('en-US') + ' ' + now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });

    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    localStorage.setItem('loginPassword', loginPassword);
    localStorage.setItem('systemPassword', systemPassword);
    localStorage.setItem('backupCounter', ordersCountSinceBackup.toString());

    localStorage.setItem('lastSessionTime', formattedDate);

    setLastSyncTime(now);
  }, [sales, purchaseInvoices, history, products, customers, suppliers, loginPassword, systemPassword, ordersCountSinceBackup]);

  const verifyLock = () => {
    if (lockPass === systemPassword) {
      if (showLock?.target === 'full_reset') {
          localStorage.clear();
          window.location.reload();
      } else if (showLock?.target === 'clear_all_history') {
          setHistory([]);
      } else if (showLock) {
          setModals(m => ({ ...m, [showLock.target]: true }));
      }
      setShowLock(null);
      setLockPass('');
      setLockError(false);
    } else {
      setLockError(true);
    }
  };

  const handleArchiveDay = useCallback(() => {
      if (sales.length === 0 && purchaseInvoices.length === 0) {
          alert('لا توجد عمليات مبيعات أو مشتريات نشطة حالياً لترحيلها.');
          return;
      }

      const confirmed = window.confirm('هل أنت متأكد من ترحيل المبيعات للأرشيف وتصفير اليوم؟ \n\nسيتم توزيع كل فاتورة حسب تاريخها الأصلي في السجلات التاريخية.');
      if (!confirmed) return;

      try {
          const currentSales = [...sales];
          const currentPurchases = [...purchaseInvoices];

          const salesMap = new Map<string, SaleItem[]>();
          currentSales.forEach(s => {
              const d = s.date;
              if (!salesMap.has(d)) salesMap.set(d, []);
              salesMap.get(d)!.push(s);
          });

          const purchaseMap = new Map<string, PurchaseInvoice[]>();
          currentPurchases.forEach(p => {
              const d = p.date;
              if (!purchaseMap.has(d)) purchaseMap.set(d, []);
              purchaseMap.get(d)!.push(p);
          });

          const allUniqueDates = Array.from(new Set([...salesMap.keys(), ...purchaseMap.keys()]));

          setHistory(prev => {
              const newHistory = [...prev];

              allUniqueDates.forEach(dateStr => {
                  const daySales = salesMap.get(dateStr) || [];
                  const dayPurchases = purchaseMap.get(dateStr) || [];

                  const rev = daySales.reduce((s, i) => s + (i.price * i.quantity), 0);
                  const exp = dayPurchases.reduce((s, i) => s + i.totalAmount, 0);

                  const existingIdx = newHistory.findIndex(h => h.date === dateStr);

                  if (existingIdx !== -1) {
                      newHistory[existingIdx] = {
                          ...newHistory[existingIdx],
                          items: [...newHistory[existingIdx].items, ...daySales],
                          purchaseInvoices: [...(newHistory[existingIdx].purchaseInvoices || []), ...dayPurchases],
                          totalRevenue: newHistory[existingIdx].totalRevenue + rev,
                          totalExpenses: newHistory[existingIdx].totalExpenses + exp,
                          totalItems: newHistory[existingIdx].totalItems + daySales.length
                      };
                  } else {
                      const refItem = daySales[0];
                      const ts = refItem ? parseInt(refItem.orderId) : Date.now();

                      newHistory.push({
                          id: `arch-${dateStr.replace(/[^0-9]/g, '')}-${Date.now()}`,
                          date: dateStr,
                          timestamp: ts,
                          items: daySales,
                          purchaseInvoices: dayPurchases,
                          totalRevenue: rev,
                          totalExpenses: exp,
                          totalItems: daySales.length
                      });
                  }
              });

              return newHistory.sort((a, b) => b.timestamp - a.timestamp);
          });

          setSales([]);
          setPurchaseInvoices([]);
          alert('تم ترحيل البيانات وتصفير اليوم بنجاح!');
      } catch (error) {
          console.error('Archive Error:', error);
          alert('حدث خطأ أثناء الترحيل.');
      }
  }, [sales, purchaseInvoices]);

  const handleExportData = async () => {
    const backup = { 
      dailySales: sales, 
      dailyPurchaseInvoices: purchaseInvoices, 
      salesHistory: history, 
      products, 
      customers, 
      suppliers, 
      loginPassword,
      systemPassword,
      exportDate: new Date().toISOString() 
    };
    const jsonString = JSON.stringify(backup);
    try {
      const stream = new Blob([jsonString]).stream();
      const compressedStream = stream.pipeThrough(new (window as any).CompressionStream('gzip'));
      const response = new Response(compressedStream);
      const compressedBlob = await response.blob();
      const url = URL.createObjectURL(compressedBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-pro-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.bak`;
      link.click();
      URL.revokeObjectURL(url);

      setOrdersCountSinceBackup(0);
      setShowBackupReminder(false);
      lastBackupTimestamp.current = Date.now();
    } catch (err) {
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cookies-bakery-legacy-${new Date().toLocaleDateString('en-GB').replace(/\//g, '-')}.json`;
      link.click();
      URL.revokeObjectURL(url);
      setOrdersCountSinceBackup(0);
      setShowBackupReminder(false);
    }
  };

  const handleImportData = async (file: File) => {
    try {
      let jsonString = '';
      if (file.name.endsWith('.bak')) {
        const stream = file.stream();
        const decompressedStream = stream.pipeThrough(new (window as any).DecompressionStream('gzip'));
        const response = new Response(decompressedStream);
        jsonString = await response.text();
      } else {
        jsonString = await file.text();
      }
      const data = JSON.parse(jsonString);
      if (data.dailySales) setSales(data.dailySales);
      if (data.dailyPurchaseInvoices) setPurchaseInvoices(data.dailyPurchaseInvoices);
      if (data.salesHistory) setHistory(data.salesHistory);
      if (data.products) setProducts(data.products);
      if (data.customers) setCustomers(data.customers);
      if (data.suppliers) setSuppliers(data.suppliers);
      if (data.loginPassword) setLoginPassword(data.loginPassword);
      if (data.systemPassword) setSystemPassword(data.systemPassword);
      alert('تمت استعادة البيانات بنجاح.');
    } catch (err) { 
      alert('خطأ في استعادة البيانات.'); 
    }
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeWelcome} lastSessionTime={previousSessionTime} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white relative">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => { setIsSyncing(true); setTimeout(() => setIsSyncing(false), 800); }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
        installPrompt={installPrompt}
        onInstall={handleInstall}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl no-print">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} systemPassword={systemPassword} />
        <POSInterface products={products} customers={customers} onCompleteOrder={completeOrder} onOpenProductManager={() => setModals(m => ({...m, products: true}))} onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} />
        <div className="mt-8">
            <SalesTable 
              items={sales} 
              onDeleteItem={(id: string) => setSales(s => s.filter(i => i.id !== id))} 
              onDeleteOrder={(oid: string) => setSales(s => s.filter(i => i.orderId !== oid))} 
              onPreviewInvoice={setInvoiceItems} 
              onUpdateItemPrice={(id: string, p: number) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))} 
            />
        </div>
      </main>

      {showBackupReminder && (
        <div className="fixed bottom-6 right-6 left-6 md:left-auto md:w-80 bg-gray-800 border border-orange-500/50 p-5 rounded-[2rem] shadow-2xl z-[150] animate-fade-up flex flex-col gap-4 no-print">
            <div className="flex items-start gap-4">
                <div className="bg-orange-500/20 p-3 rounded-2xl text-orange-500 shrink-0"><AlertCircle size={24} /></div>
                <div className="flex-1 text-right">
                    <h4 className="text-white font-black text-sm">تأمين البيانات مطلوب</h4>
                    <p className="text-gray-400 text-[10px] font-bold mt-1 leading-relaxed">يرجى أخذ نسخة احتياطية الآن لضمان سلامة بيانات مبيعاتك.</p>
                </div>
                <button onClick={() => setShowBackupReminder(false)} className="text-gray-500 hover:text-white"><X size={18} /></button>
            </div>
            <button onClick={handleExportData} className="w-full bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95"><Download size={14} /> نسخ مضغوط الآن</button>
        </div>
      )}

      <footer className="mt-12 py-8 border-t border-gray-800/50 text-center no-print">
         <button onClick={() => handleOpenProtected('full_reset')} className="text-gray-700 text-[10px] font-bold tracking-widest uppercase">نظام مبيعات كوكيز v2.6.5 • 2026</button>
      </footer>
      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && <ExpensesModal isOpen={modals.expenses} onClose={() => setModals(m => ({...m, expenses: false}))} currentPurchases={purchaseInvoices} archivedHistory={history} onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))} onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} suppliers={suppliers} onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} />}
        {modals.history && <HistoryModal history={history} currentSales={sales} onClose={() => setModals(m => ({...m, history: false}))} onPreviewInvoice={setInvoiceItems} onUpdateOrder={handleUpdateArchivedOrder} onDeleteArchivedOrder={handleDeleteArchivedOrder} onDeleteArchivedDay={handleDeleteArchivedDay} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={handleUpdateProduct} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} onArchiveDay={handleArchiveDay} systemPassword={systemPassword} setSystemPassword={setSystemPassword} loginPassword={loginPassword} setLoginPassword={setLoginPassword} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>
      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm no-print">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">أدخل كلمة المرور للمتابعة</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { X, Download, Upload, Database, AlertTriangle, FileJson, Trash2, Lock, KeyRound, CheckCircle2, Archive, ShieldCheck, ChevronDown, ChevronUp } from 'lucide-react';

interface DataManagementModalProps {
  onExport: () => void;
  onImport: (file: File) => void;
  onArchiveDay: () => void;
  onClose: () => void;
  systemPassword: string;
  setSystemPassword: (pass: string) => void;
  loginPassword: string;
  setLoginPassword: (pass: string) => void;
}

export const DataManagementModal: React.FC<DataManagementModalProps> = ({ 
  onExport, onImport, onArchiveDay, onClose, systemPassword, setSystemPassword, loginPassword, setLoginPassword 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [showPassField, setShowPassField] = useState(false);
  const [restorePass, setRestorePass] = useState('');
  const [passError, setPassError] = useState(false);
  const [activeSection, setActiveSection] = useState<'main' | 'security'>('main');

  const [passChange, setPassChange] = useState({ old: '', new: '', confirm: '' });
  const [sysPassChange, setSysPassChange] = useState({ old: '', new: '', confirm: '' });
  const [passChangeMsg, setPassChangeMsg] = useState({ text: '', type: '' as 'err' | 'success' | '' });
  const [sysPassChangeMsg, setSysPassChangeMsg] = useState({ text: '', type: '' as 'err' | 'success' | '' });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setSelectedFile(file);
    if (e.target) e.target.value = '';
  };

  const handleConfirmRestore = () => {
    if (restorePass === systemPassword) {
      if (!selectedFile) return;
      onImport(selectedFile);
      onClose();
    } else {
      setPassError(true);
      setRestorePass('');
    }
  };

  const handleLoginPasswordChange = () => {
      if (passChange.old !== loginPassword) {
          setPassChangeMsg({ text: 'كلمة مرور الدخول الحالية غير صحيحة', type: 'err' });
          return;
      }
      if (passChange.new.length < 4) {
          setPassChangeMsg({ text: 'كلمة المرور يجب أن تكون 4 رموز على الأقل', type: 'err' });
          return;
      }
      if (passChange.new !== passChange.confirm) {
          setPassChangeMsg({ text: 'تأكيد كلمة المرور غير متطابق', type: 'err' });
          return;
      }

      setLoginPassword(passChange.new);
      setPassChange({ old: '', new: '', confirm: '' });
      setPassChangeMsg({ text: 'تم تغيير كلمة مرور الدخول بنجاح', type: 'success' });
      setTimeout(() => setPassChangeMsg({ text: '', type: '' }), 3000);
  };

  const handleSystemPasswordChange = () => {
      if (sysPassChange.old !== systemPassword) {
          setSysPassChangeMsg({ text: 'كلمة مرور العمليات الحالية غير صحيحة', type: 'err' });
          return;
      }
      if (sysPassChange.new.length < 4) {
          setSysPassChangeMsg({ text: 'كلمة المرور يجب أن تكون 4 رموز على الأقل', type: 'err' });
          return;
      }
      if (sysPassChange.new !== sysPassChange.confirm) {
          setSysPassChangeMsg({ text: 'تأكيد كلمة المرور غير متطابق', type: 'err' });
          return;
      }

      setSystemPassword(sysPassChange.new);
      setSysPassChange({ old: '', new: '', confirm: '' });
      setSysPassChangeMsg({ text: 'تم تغيير كلمة مرور العمليات بنجاح', type: 'success' });
      setTimeout(() => setSysPassChangeMsg({ text: '', type: '' }), 3000);
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-3xl w-full max-w-lg shadow-2xl border border-gray-700 flex flex-col overflow-hidden animate-fade-up max-h-[90vh]">
        <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50 shrink-0">
          <div className="flex items-center gap-2 text-white">
            <Database size={20} className="text-[#FA8072]" />
            <h3 className="font-black text-lg">إعدادات النظام والبيانات</h3>
          </div>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white transition-colors"><X size={20} /></button>
        </div>

        <div className="p-6 overflow-y-auto space-y-6 custom-scrollbar">

            {activeSection === 'main' ? (
              <>
                <div className="bg-[#FA8072]/10 p-5 rounded-2xl border border-[#FA8072]/20 space-y-4">
                    <h4 className="text-white font-black flex items-center gap-2 text-sm">
                        <Archive size={16} className="text-orange-500" /> إغلاق وترحيل اليوم
                    </h4>
                    <p className="text-gray-400 text-[10px] font-bold leading-relaxed">سيتم نقل جميع مبيعات ومشتريات اليوم النشطة إلى السجلات التاريخية وتصفير النظام.</p>
                    <button onClick={() => { onArchiveDay(); onClose(); }} className="w-full bg-gradient-to-r from-orange-600 to-red-600 hover:from-orange-500 hover:to-red-500 text-white py-3.5 rounded-xl font-black text-xs transition-all shadow-xl active:scale-95">ترحيل مبيعات اليوم وتصفير النظام</button>
                </div>

                <button 
                  onClick={() => setActiveSection('security')}
                  className="w-full bg-gray-900/60 p-5 rounded-2xl border border-gray-700 flex items-center justify-between hover:border-[#FA8072] transition-all group"
                >
                    <div className="flex items-center gap-4">
                        <div className="bg-blue-500/10 p-3 rounded-2xl text-blue-400 group-hover:bg-blue-500 group-hover:text-white transition-all"><ShieldCheck size={24} /></div>
                        <div className="text-right">
                            <h4 className="text-white font-black text-sm">الأمان والخصوصية</h4>
                            <p className="text-gray-500 text-[10px] font-bold mt-0.5">تغيير كلمات مرور الدخول والتبويبات</p>
                        </div>
                    </div>
                    <ChevronDown size={18} className="text-gray-600 group-hover:text-[#FA8072] -rotate-90" />
                </button>

                <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700">
                    <h4 className="text-white font-black mb-3 text-sm flex items-center gap-2"><Download size={16} className="text-blue-400" /> نسخة احتياطية (.bak)</h4>
                    <p className="text-gray-500 text-[10px] mb-4 font-bold leading-relaxed">تصدير قاعدة البيانات بصيغة مضغوطة تشمل (المبيعات، المشتريات، المنتجات، وكلمات المرور).</p>
                    <button onClick={onExport} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-xl font-black flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95"><FileJson size={20} /> تصدير نسخة مضغوطة</button>
                </div>

                <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700">
                    <h4 className="text-white font-black mb-3 text-sm flex items-center gap-2"><Upload size={16} className="text-green-400" /> استعادة البيانات</h4>
                    <div className="bg-red-500/10 border border-red-500/20 rounded-xl p-3 mb-4 flex items-start gap-3">
                        <AlertTriangle size={16} className="text-red-500 shrink-0 mt-1" />
                        <p className="text-[10px] text-red-200 font-bold leading-relaxed">تنبيه: استعادة البيانات ستحذف كل شيء حالي وتستبدله بمحتوى الملف.</p>
                    </div>

                    <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".bak,.json" className="hidden" />
                    {!selectedFile ? (
                        <button onClick={() => fileInputRef.current?.click()} className="w-full bg-gray-700 hover:bg-gray-600 text-white py-3 rounded-xl font-black text-xs border border-gray-600 border-dashed flex items-center justify-center gap-2 transition-colors">اختيار ملف النسخة (.bak)</button>
                    ) : (
                        <div className="space-y-3">
                            <div className="bg-gray-800 p-4 rounded-xl border border-green-500/30 flex items-center justify-between"><span className="text-xs text-white truncate max-w-[150px] font-black">{selectedFile.name}</span><button onClick={() => setSelectedFile(null)} className="text-red-400"><Trash2 size={18} /></button></div>
                            {!showPassField ? (
                               <button onClick={() => setShowPassField(true)} className="w-full bg-orange-600 text-white py-3.5 rounded-xl font-black shadow-lg">بدء عملية الاستعادة</button>
                            ) : (
                               <div className="space-y-3 p-3 bg-gray-950 rounded-xl border border-gray-600">
                                   <input type="password" value={restorePass} onChange={e => { setRestorePass(e.target.value); setPassError(false); }} placeholder="أدخل كلمة مرور العمليات للتأكيد" className={`w-full bg-gray-800 border ${passError ? 'border-red-500' : 'border-gray-700'} text-white rounded-lg py-3 text-center outline-none`} autoFocus />
                                   {passError && <p className="text-red-500 text-[9px] text-center font-bold">الرمز غير صحيح!</p>}
                                   <button onClick={handleConfirmRestore} className="w-full bg-red-600 text-white py-2.5 rounded-lg font-black text-xs">تأكيد الاستبدال النهائي</button>
                               </div>
                            )}
                        </div>
                    )}
                </div>
              </>
            ) : (
              <div className="space-y-6 animate-fade-up">
                  <button onClick={() => setActiveSection('main')} className="flex items-center gap-2 text-blue-400 font-black text-[10px] uppercase tracking-widest mb-2"><ArrowRight size={14} /> العودة للبيانات</button>

                  {/* Password Level 1: Login */}
                  <div className="bg-gray-900/50 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="flex items-center gap-3">
                          <div className="bg-orange-500/10 p-2 rounded-lg text-orange-500"><Lock size={16} /></div>
                          <h4 className="text-white font-black text-sm">كلمة مرور تسجيل الدخول</h4>
                      </div>
                      <div className="space-y-3">
                          <input type="password" value={passChange.old} onChange={e => setPassChange({...passChange, old: e.target.value})} placeholder="كلمة المرور الحالية" className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl px-4 py-2.5 text-xs outline-none" />
                          <div className="grid grid-cols-2 gap-2">
                              <input type="password" value={passChange.new} onChange={e => setPassChange({...passChange, new: e.target.value})} placeholder="الرمز الجديد" className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl px-4 py-2.5 text-xs outline-none" />
                              <input type="password" value={passChange.confirm} onChange={e => setPassChange({...passChange, confirm: e.target.value})} placeholder="تأكيد الرمز" className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl px-4 py-2.5 text-xs outline-none" />
                          </div>
                          {passChangeMsg.text && <div className={`text-[10px] font-bold text-center flex items-center justify-center gap-1 ${passChangeMsg.type === 'err' ? 'text-red-400' : 'text-green-400'}`}>{passChangeMsg.text}</div>}
                          <button onClick={handleLoginPasswordChange} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2.5 rounded-xl font-black text-xs transition-all">تحديث كلمة مرور الدخول</button>
                      </div>
                  </div>

                  {/* Password Level 2: Tabs/System */}
                  <div className="bg-gray-900/50 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="flex items-center gap-3">
                          <div className="bg-[#FA8072]/10 p-2 rounded-lg text-[#FA8072]"><KeyRound size={16} /></div>
                          <h4 className="text-white font-black text-sm">كلمة مرور العمليات والتبويبات</h4>
                      </div>
                      <div className="space-y-3">
                          <input type="password" value={sysPassChange.old} onChange={e => setSysPassChange({...sysPassChange, old: e.target.value})} placeholder="كلمة مرور العمليات الحالية" className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl px-4 py-2.5 text-xs outline-none" />
                          <div className="grid grid-cols-2 gap-2">
                              <input type="password" value={sysPassChange.new} onChange={e => setSysPassChange({...sysPassChange, new: e.target.value})} placeholder="الرمز الجديد" className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl px-4 py-2.5 text-xs outline-none" />
                              <input type="password" value={sysPassChange.confirm} onChange={e => setSysPassChange({...sysPassChange, confirm: e.target.value})} placeholder="تأكيد الرمز" className="w-full bg-gray-800 border border-gray-700 text-white rounded-xl px-4 py-2.5 text-xs outline-none" />
                          </div>
