                        className="w-full bg-gray-900 border border-gray-700 text-white p-4 rounded-2xl text-center outline-none focus:border-red-500 font-black text-xl tabular-nums"
                        autoFocus
                      />
                      {parseFloat(actionQty) > consumeDialog.available && (
                          <p className="text-red-500 text-[9px] text-center font-bold animate-pulse">تنبيه: الكمية المدخلة أكبر من الرصيد المتاح!</p>
                      )}
                      <div className="flex gap-2">
                        <button onClick={handleConsume} className="flex-1 bg-red-600 text-white py-4 rounded-2xl font-black text-xs shadow-lg active:scale-95 transition-all">تأكيد السحب</button>
                        <button onClick={() => {setConsumeDialog(null); setActionQty('');}} className="flex-1 bg-gray-700 text-white py-4 rounded-2xl font-black text-xs">إلغاء</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Edit Quantity Dialog */}
      {editQtyDialog && (
          <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
              <div className="bg-gray-800 border border-indigo-500/50 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up">
                  <div className="text-center mb-6">
                      <div className="w-12 h-12 bg-indigo-500/20 rounded-full flex items-center justify-center mx-auto mb-3"><Edit3 className="text-indigo-400" size={24} /></div>
                      <h3 className="text-white font-black text-lg">تعديل رصيد مادة</h3>
                      <p className="text-gray-500 text-[10px] font-bold mt-1 uppercase">مادة: {editQtyDialog.name}</p>
                  </div>
                  <div className="space-y-4">
                      <div className="text-center mb-1">
                          <span className="text-[9px] text-gray-500 font-bold uppercase">الكمية الحالية: {editQtyDialog.current}</span>
                      </div>
                      <input 
                        type="number" 
                        value={actionQty} 
                        onChange={e => setActionQty(e.target.value)} 
                        placeholder="أدخل الكمية الجديدة" 
                        className="w-full bg-gray-900 border border-gray-700 text-white p-4 rounded-2xl text-center outline-none focus:border-indigo-400 font-black text-xl tabular-nums"
                        autoFocus
                      />
                      <div className="flex gap-2">
                        <button onClick={handleUpdateStockQty} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black text-xs shadow-lg active:scale-95 transition-all">تحديث الرصيد</button>
                        <button onClick={() => {setEditQtyDialog(null); setActionQty('');}} className="flex-1 bg-gray-700 text-white py-4 rounded-2xl font-black text-xs">إلغاء</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {invoiceToPrint && <Suspense fallback={null}><PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} /></Suspense>}
    </div>
  );
};

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, UserPlus, Printer, FileText, Store, Folder, CalendarDays, ArrowRight, Zap, ChevronDown, ChevronUp, Edit3, RotateCcw, Search, Package, ArrowDownLeft, AlertTriangle, Layers, Info } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier, StockItem } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onUpdateInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier: (id: string) => void;
  inventory: StockItem[];
  setInventory: React.Dispatch<React.SetStateAction<StockItem[]>>;
}

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, archivedHistory, onAddInvoice, onUpdateInvoice, onDeleteInvoice, isOpen, onClose, suppliers = [], onAddSupplier, onDeleteSupplier, inventory, setInventory
}) => {
  const [activeTab, setActiveTab] = useState<'new' | 'history' | 'suppliers' | 'inventory'>('new');
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', unitPrice: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);

  // Inventory Management State
  const [showAddStock, setShowAddStock] = useState(false);
  const [newStock, setNewStock] = useState({ name: '', unitType: 'kg' as 'kg'|'piece', minThreshold: 1 });
  const [consumeDialog, setConsumeDialog] = useState<{id: string, name: string, available: number} | null>(null);
  const [editQtyDialog, setEditQtyDialog] = useState<{id: string, name: string, current: number} | null>(null);
  const [actionQty, setActionQty] = useState('');

  const handleAddStockItem = () => {
    if (!newStock.name) return;
    const item: StockItem = {
        id: Date.now().toString(),
        name: newStock.name,
        currentQuantity: 0,
        unitType: newStock.unitType,
        minThreshold: newStock.minThreshold,
        lastUpdated: new Date().toLocaleDateString()
    };
    setInventory(prev => [...prev, item]);
    setNewStock({ name: '', unitType: 'kg', minThreshold: 1 });
    setShowAddStock(false);
  };

  const handleConsume = () => {
    if (!consumeDialog || !actionQty) return;
    const qtyToSubtract = parseFloat(actionQty);
    if (isNaN(qtyToSubtract)) return;

    setInventory(prev => prev.map(item => {
        if (item.id === consumeDialog.id) {
            // السماح بالأرقام السالبة لتوضيح العجز الفعلي
            const newQuantity = item.currentQuantity - qtyToSubtract;
            return { 
                ...item, 
                currentQuantity: newQuantity, 
                lastUpdated: new Date().toLocaleDateString() 
            };
        }
        return item;
    }));
    setConsumeDialog(null);
    setActionQty('');
  };

  const handleUpdateStockQty = () => {
    if (!editQtyDialog || !actionQty) return;
    const newQty = parseFloat(actionQty);
    if (isNaN(newQty)) return;

    setInventory(prev => prev.map(item => 
        item.id === editQtyDialog.id 
        ? { 
            ...item, 
            currentQuantity: newQty, // السماح بإدخال أي قيمة حتى لو كانت سالبة
            lastUpdated: new Date().toLocaleDateString() 
          }
        : item
    ));
    setEditQtyDialog(null);
    setActionQty('');
  };

  const addItemToInvoice = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.unitPrice) return;

      const existsInStock = inventory.some(i => i.name === itemInputs.name);
      if (!existsInStock) {
          alert('خطأ: هذه المادة غير معرفة في المستودع. يرجى تعريف المادة أولاً من تبويب المستودع قبل شرائها.');
          return;
      }

      const q = parseFloat(itemInputs.quantity); 
      const price = parseFloat(itemInputs.unitPrice);
      setCurrentInvoiceItems(prev => [...prev, { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: price, total: q * price }]);
      setItemInputs({ name: '', quantity: '', unitPrice: '' });
  };

  const handleSaveInvoice = () => {
      const supplier = suppliers.find(s => s.id === selectedSupplierId);
      if (!supplier || currentInvoiceItems.length === 0) return alert('يرجى تحديد مورد وإضافة مواد');

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      const invoiceData: PurchaseInvoice = { 
          id: editingInvoiceId || Date.now().toString(), 
          supplierName: supplier.name, 
          date: new Date().toLocaleDateString('ar-SY'), 
          timestamp: Date.now(), 
          items: currentInvoiceItems, 
          totalAmount, 
          paymentStatus 
      };

      setInventory(prev => {
          let updated = [...prev];
          currentInvoiceItems.forEach(purchaseItem => {
              const stockIdx = updated.findIndex(s => s.name === purchaseItem.name);
              if (stockIdx > -1) {
                  updated[stockIdx] = { 
                      ...updated[stockIdx], 
                      currentQuantity: updated[stockIdx].currentQuantity + purchaseItem.quantity,
                      lastUpdated: new Date().toLocaleDateString()
                  };
              }
          });
          return updated;
      });

      if (editingInvoiceId) onUpdateInvoice(invoiceData);
      else onAddInvoice(invoiceData);

      setSelectedSupplierId(''); setCurrentInvoiceItems([]); setEditingInvoiceId(null);
      setActiveTab('inventory');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-2xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden">

        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900 shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-[#FA8072]/20 p-2.5 rounded-2xl"><Package className="text-[#FA8072]" size={24} /></div>
            <h3 className="font-black text-xl text-white">المخزون والمستودع</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-xl transition-all text-gray-400"><X size={24} /></button>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-900/30 overflow-x-auto">
            <button onClick={() => setActiveTab('inventory')} className={`flex-1 min-w-[100px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'inventory' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500'}`}>
                <Layers size={16} /> المستودع
            </button>
            <button onClick={() => setActiveTab('new')} className={`flex-1 min-w-[100px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'new' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500'}`}>
                <ShoppingCart size={16} /> شراء جديد
            </button>
            <button onClick={() => setActiveTab('history')} className={`flex-1 min-w-[100px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'history' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>
                <CalendarDays size={16} /> السجل
            </button>
            <button onClick={() => setActiveTab('suppliers')} className={`flex-1 min-w-[100px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'suppliers' ? 'bg-gray-700 text-white' : 'text-gray-500'}`}>
                <Store size={16} /> الموردين
            </button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">

          {activeTab === 'inventory' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="flex justify-between items-center mb-4">
                      <h4 className="text-white font-black text-sm flex items-center gap-2"><Package size={16} className="text-indigo-400" /> جرد المستودع الحالي</h4>
                      <button onClick={() => setShowAddStock(!showAddStock)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-xl text-[10px] font-black flex items-center gap-2 transition-all">
                          {showAddStock ? <X size={14} /> : <Plus size={14} />} تعريف مادة خام
                      </button>
                  </div>

                  {showAddStock && (
                      <div className="bg-gray-900 border border-indigo-500/30 p-4 rounded-2xl mb-6 space-y-4 shadow-xl">
                          <p className="text-[10px] text-gray-400 font-bold mb-2">أضف المواد التي تشتريها وتريد جردها (مثل الطحين، السكر..)</p>
                          <div className="grid grid-cols-2 gap-3">
                              <input type="text" value={newStock.name} onChange={e => setNewStock({...newStock, name: e.target.value})} placeholder="اسم المادة الخام" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs" />
                              <select value={newStock.unitType} onChange={e => setNewStock({...newStock, unitType: e.target.value as any})} className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs">
                                  <option value="kg">كيلو (kg)</option>
                                  <option value="piece">قطعة (pcs)</option>
                              </select>
                          </div>
                          <button onClick={handleAddStockItem} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black text-xs">حفظ المادة في المستودع</button>
                      </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      {inventory.map(item => (
                          <div key={item.id} className="bg-gray-900/60 p-5 rounded-3xl border border-gray-700 group hover:border-indigo-500/50 transition-all">
                              <div className="flex justify-between items-start mb-4">
                                  <div className="flex flex-col">
                                      <span className="text-white font-black text-sm">{item.name}</span>
                                      <span className="text-[9px] text-gray-500 font-bold">آخر تحديث: {item.lastUpdated}</span>
                                  </div>
                                  <button onClick={() => { setEditQtyDialog({id: item.id, name: item.name, current: item.currentQuantity}); setActionQty(item.currentQuantity.toString()); }} className="bg-gray-800 p-2 rounded-xl text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all"><Edit3 size={18} /></button>
                              </div>
                              <div className="flex items-center justify-between mb-4">
                                  <div className="flex items-baseline gap-1">
                                      <span className={`text-3xl font-black tabular-nums ${item.currentQuantity <= item.minThreshold ? 'text-red-500' : 'text-green-500'}`}>
                                          {item.currentQuantity}
                                      </span>
                                      <span className="text-[10px] text-gray-500 font-bold">{item.unitType === 'kg' ? 'كيلو' : 'قطعة'}</span>
                                  </div>
                                  <button onClick={() => { setConsumeDialog({id: item.id, name: item.name, available: item.currentQuantity}); setActionQty(''); }} className="bg-red-900/20 text-red-500 hover:bg-red-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black flex items-center gap-1.5 transition-all border border-red-500/20">
                                      <ArrowDownLeft size={14} /> استهلاك
                                  </button>
                              </div>
                              {item.currentQuantity <= item.minThreshold && (
                                  <div className="flex items-center gap-2 text-red-500 text-[9px] font-black animate-pulse bg-red-500/5 p-2 rounded-lg">
                                      <AlertTriangle size={12} /> {item.currentQuantity < 0 ? 'يوجد عجز في المادة!' : 'الكمية قاربت على النفاذ!'}
                                  </div>
                              )}
                          </div>
                      ))}
                      {inventory.length === 0 && (
                          <div className="col-span-full py-20 text-center text-gray-600 italic text-sm">لم يتم تعريف أي مواد خام في المستودع بعد.</div>
                      )}
                  </div>
              </div>
          )}

          {activeTab === 'new' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="bg-indigo-600/10 border border-indigo-600/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
                      <Info size={20} className="text-indigo-400 shrink-0" />
                      <p className="text-[10px] text-indigo-200 font-bold leading-relaxed">تنبيه المشتريات: لن يقبل النظام إضافة أي مادة إلا إذا كانت معرفة في تبويب "المستودع" أولاً.</p>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black pr-1">تحديد المورد:</label>
                        <select value={selectedSupplierId} onChange={e => setSelectedSupplierId(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs font-bold outline-none focus:border-[#FA8072]">
                            <option value="">اختر مورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black pr-1">حالة الدفع:</label>
                        <div className="flex bg-gray-900 p-1 rounded-xl border border-gray-700">
                            <button onClick={() => setPaymentStatus('paid')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'paid' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-500'}`}>نقدي</button>
                            <button onClick={() => setPaymentStatus('credit')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'credit' ? 'bg-orange-600 text-white shadow-lg' : 'text-gray-500'}`}>آجل</button>
                        </div>
                    </div>
                  </div>

                  <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                          <div className="relative group">
                              <input type="text" list="stock-options" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="اختر مادة من المستودع..." className="w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs font-bold focus:border-indigo-500 outline-none" />
                              <datalist id="stock-options">
                                  {inventory.map(i => <option key={i.id} value={i.name} />)}
                              </datalist>
                              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-600"><Layers size={14} /></div>
                          </div>
                          <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية المشتراة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-center font-bold outline-none focus:border-green-500" />
                          <input type="number" value={itemInputs.unitPrice} onChange={e => setItemInputs({...itemInputs, unitPrice: e.target.value})} placeholder="سعر الشراء" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-center font-bold outline-none focus:border-green-500" />
                      </div>
                      <button onClick={addItemToInvoice} className="w-full bg-indigo-600 hover:bg-indigo-500 text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all shadow-lg">
                          <Plus size={16} /> إضافة مادة للفاتورة
                      </button>
                  </div>

                  <div className="bg-gray-950/30 border border-gray-700 rounded-2xl overflow-hidden shadow-inner">
                      <table className="w-full text-xs text-right">
                          <thead className="bg-gray-900 text-gray-500 font-black uppercase text-[10px]"><tr><th className="p-4">الصنف</th><th className="p-4 text-center">الكمية</th><th className="p-4">الإجمالي</th><th className="p-4"></th></tr></thead>
                          <tbody className="divide-y divide-gray-800">
                              {currentInvoiceItems.map(item => (
                                  <tr key={item.id} className="hover:bg-gray-800/50">
                                      <td className="p-4 text-white font-black">{item.name}</td>
                                      <td className="p-4 text-center text-gray-400 font-bold tabular-nums">{item.quantity}</td>
                                      <td className="p-4 text-[#FA8072] font-black tabular-nums">{item.total.toLocaleString()}</td>
                                      <td className="p-4"><button onClick={() => setCurrentInvoiceItems(prev => prev.filter(i => i.id !== item.id))} className="text-gray-600 hover:text-red-500 p-1"><Trash2 size={16}/></button></td>
                                  </tr>
                              ))}
                              {currentInvoiceItems.length === 0 && <tr><td colSpan={4} className="p-16 text-center text-gray-700 italic text-sm">السلة فارغة، ابدأ باختيار مواد من المستودع</td></tr>}
                          </tbody>
                      </table>
                  </div>

                  <div className="flex items-center justify-between pt-6 border-t border-gray-700">
                      <div className="text-2xl font-black text-red-500 tabular-nums">
                          {currentInvoiceItems.reduce((s,i) => s + i.total, 0).toLocaleString()} <span className="text-[10px] text-gray-600 uppercase">ل.س</span>
                      </div>
                      <button onClick={handleSaveInvoice} className="bg-green-600 hover:bg-green-500 text-white px-8 py-4 rounded-2xl font-black text-sm flex items-center gap-3 shadow-xl transition-all active:scale-95">
                          <FileText size={20} /> حفظ الفاتورة وتحديث المستودع
                      </button>
                  </div>
              </div>
          )}

          {activeTab === 'history' && (
              <div className="space-y-4 animate-fade-up">
                  {currentPurchases.map(inv => (
                      <div key={inv.id} className="bg-gray-900/40 p-4 rounded-3xl border border-gray-700 flex justify-between items-center group hover:bg-gray-900/60 transition-all">
                          <div className="flex items-center gap-4">
                              <div className="bg-gray-800 p-3 rounded-2xl text-red-400"><ShoppingCart size={18} /></div>
                              <div className="flex flex-col">
                                  <span className="text-white text-xs font-black">{inv.supplierName}</span>
                                  <span className="text-[9px] text-gray-500 font-bold tabular-nums">{inv.date} • {inv.totalAmount.toLocaleString()} ل.س</span>
                              </div>
                          </div>
                          <div className="flex gap-2">
                              <button onClick={() => setInvoiceToPrint(inv)} className="p-2 bg-gray-800 rounded-xl text-white hover:bg-blue-600 transition-colors shadow-lg"><Printer size={16}/></button>
                              <button onClick={() => onDeleteInvoice(inv.id)} className="p-2 text-gray-600 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                          </div>
                      </div>
                  ))}
                  {currentPurchases.length === 0 && <div className="py-20 text-center text-gray-700 italic">لا توجد فواتير شراء نشطة اليوم</div>}
              </div>
          )}

          {activeTab === 'suppliers' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="bg-gray-900/40 p-6 rounded-2xl border border-gray-700 space-y-4">
                      <h4 className="text-white font-black text-sm">إضافة مورد جديد</h4>
                      <div className="grid grid-cols-2 gap-3">
                          <input type="text" placeholder="اسم المورد" id="sup-name" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs outline-none focus:border-[#FA8072]" />
                          <input type="text" placeholder="الهاتف" id="sup-phone" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs outline-none focus:border-[#FA8072] dir-ltr text-right" />
                      </div>
                      <button onClick={() => {
                          const n = (document.getElementById('sup-name') as HTMLInputElement).value;
                          const p = (document.getElementById('sup-phone') as HTMLInputElement).value;
                          if(n) { onAddSupplier({name: n, phone: p}); (document.getElementById('sup-name') as HTMLInputElement).value = ''; (document.getElementById('sup-phone') as HTMLInputElement).value = ''; }
                      }} className="w-full bg-[#FA8072] hover:bg-orange-600 text-white py-3 rounded-xl font-black text-xs transition-all shadow-lg active:scale-95">إضافة المورد لقاعدة البيانات</button>
                  </div>
                  <div className="grid gap-2">
                      {suppliers.map(s => (
                          <div key={s.id} className="bg-gray-900/40 p-4 rounded-2xl border border-gray-700 flex justify-between items-center group hover:bg-gray-900/60 transition-all">
                              <div className="flex flex-col">
                                <span className="text-white font-black text-xs">{s.name}</span>
                                {s.phone && <span className="text-[9px] text-gray-500 font-bold">{s.phone}</span>}
                              </div>
                              <button onClick={() => onDeleteSupplier(s.id)} className="text-gray-600 hover:text-red-500 p-1"><Trash2 size={16}/></button>
                          </div>
                      ))}
                  </div>
              </div>
          )}
        </div>
      </div>

      {/* Consume Quantity Dialog */}
      {consumeDialog && (
          <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
              <div className="bg-gray-800 border border-red-500/50 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up">
                  <div className="text-center mb-6">
                      <div className="w-12 h-12 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-3"><ArrowDownLeft className="text-red-500" size={24} /></div>
                      <h3 className="text-white font-black text-lg">استهلاك من المستودع</h3>
                      <div className="bg-gray-900 py-2 px-4 rounded-xl mt-2 flex flex-col items-center">
                          <p className="text-gray-500 text-[9px] font-bold uppercase">مادة: {consumeDialog.name}</p>
                          <p className="text-green-500 text-[10px] font-black mt-1 uppercase">المتوفر حالياً: {consumeDialog.available}</p>
                      </div>
                  </div>
                  <div className="space-y-4">
                      <input 
                        type="number" 
                        value={actionQty} 
                        onChange={e => setActionQty(e.target.value)} 
                        placeholder="الكمية المراد سحبها" 
                        className="w-full bg-gray-900 border border-gray-700 text-white p-4 rounded-2xl text-center outline-none focus:border-red-500 font-black text-xl tabular-nums"
                        autoFocus
                      />
                      {parseFloat(actionQty) > consumeDialog.available && (
                          <p className="text-orange-400 text-[9px] text-center font-bold animate-pulse">تنبيه: سيصبح الرصيد سالباً (عجز في المادة)</p>
                      )}
                      <div className="flex gap-2">
                        <button onClick={handleConsume} className="flex-1 bg-red-600 text-white py-4 rounded-2xl font-black text-xs shadow-lg active:scale-95 transition-all">تأكيد السحب</button>
                        <button onClick={() => {setConsumeDialog(null); setActionQty('');}} className="flex-1 bg-gray-700 text-white py-4 rounded-2xl font-black text-xs">إلغاء</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Edit Quantity Dialog */}
      {editQtyDialog && (
          <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
              <div className="bg-gray-800 border border-indigo-500/50 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up">
                  <div className="text-center mb-6">
                      <div className="w-12 h-12 bg-indigo-500/20 rounded-full flex items-center justify-center mx-auto mb-3"><Edit3 className="text-indigo-400" size={24} /></div>
                      <h3 className="text-white font-black text-lg">تعديل رصيد مادة</h3>
                      <p className="text-gray-500 text-[10px] font-bold mt-1 uppercase">مادة: {editQtyDialog.name}</p>
                  </div>
                  <div className="space-y-4">
                      <div className="text-center mb-1">
                          <span className="text-[9px] text-gray-500 font-bold uppercase">الكمية الحالية: {editQtyDialog.current}</span>
                      </div>
                      <input 
                        type="number" 
                        value={actionQty} 
                        onChange={e => setActionQty(e.target.value)} 
                        placeholder="أدخل الكمية الجديدة" 
                        className="w-full bg-gray-900 border border-gray-700 text-white p-4 rounded-2xl text-center outline-none focus:border-indigo-400 font-black text-xl tabular-nums"
                        autoFocus
                      />
                      <div className="flex gap-2">
                        <button onClick={handleUpdateStockQty} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-black text-xs shadow-lg active:scale-95 transition-all">تحديث الرصيد</button>
                        <button onClick={() => {setEditQtyDialog(null); setActionQty('');}} className="flex-1 bg-gray-700 text-white py-4 rounded-2xl font-black text-xs">إلغاء</button>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {invoiceToPrint && <Suspense fallback={null}><PurchasePrintModal invoice={invoiceToPrint} onClose={() => setInvoiceToPrint(null)} /></Suspense>}
    </div>
  );
};

export type UnitType = 'piece' | 'kg';
export type SaleType = 'retail' | 'wholesale';
export type PaymentStatus = 'paid' | 'credit';

export interface Customer {
  id: string;
  name: string;
  phone?: string;
}

export interface Supplier {
  id: string;
  name: string;
  phone?: string;
  notes?: string;
}

export interface Employee {
  id: string;
  name: string;
  position?: string;
}

export interface SalaryPayment {
  id: string;
  employeeId: string;
  employeeName: string;
  amount: number;
  date: string;
  month: string;
  notes?: string;
}

export interface SaleItem {
  id: string;
  orderId: string;
  customerNumber: number;
  customerName?: string; 
  customerId?: string; 
  saleType: SaleType; 
  name: string;
  price: number;
  costPrice: number; 
  quantity: number;
  unitType: UnitType;
  time: string;
  date: string; 
  barcode?: string;
}

export interface PurchaseItem {
  id: string;
  name: string;
  quantity: number;
  cost: number;
  total: number;
}

export interface PurchaseInvoice {
  id: string;
  supplierName: string;
  date: string;
  timestamp: number;
  items: PurchaseItem[];
  totalAmount: number;
  paymentStatus: PaymentStatus; 
}

export interface Product {
  id: string;
  name: string;
  price: number;
  wholesalePrice: number; 
  costPrice: number; 
  unitType: UnitType;
  barcode?: string;
}

export interface StockItem {
  id: string;
  name: string;
  currentQuantity: number;
  unitType: UnitType;
  minThreshold: number; // تنبيه عند الوصول لهذه الكمية
  lastUpdated: string;
}

export interface ArchivedDay {
  id: string;
  date: string;
  timestamp: number;
  totalRevenue: number;
  totalExpenses: number; 
  totalItems: number;
  items: SaleItem[];
  purchaseInvoices: PurchaseInvoice[];
  salaryPayments?: SalaryPayment[];
}

import React, { useState, useEffect, Suspense, useCallback, useRef } from 'react';
import { Header } from './components/Header';
import { POSInterface } from './components/RecipeGenerator';
import { SalesTable } from './components/Menu';
import { Summary } from './components/InfoBox';
import { Login } from './components/Login';
import { SaleItem, Product, ArchivedDay, SaleType, Customer, PurchaseInvoice, Supplier, StockItem, Employee, SalaryPayment } from './types';
import { Loader2, X, ShieldCheck, Wifi, WifiOff, CloudDownload, CheckCircle2, AlertCircle, Download, AlertTriangle, Clock } from 'lucide-react';

const InvoiceModal = React.lazy(() => import('./components/InvoiceModal').then(m => ({ default: m.InvoiceModal })));
const ProductManager = React.lazy(() => import('./components/ProductManager').then(m => ({ default: m.ProductManager })));
const HistoryModal = React.lazy(() => import('./components/HistoryModal').then(m => ({ default: m.HistoryModal })));
const DataManagementModal = React.lazy(() => import('./components/DataManagementModal').then(m => ({ default: m.DataManagementModal })));
const CustomerManager = React.lazy(() => import('./components/CustomerManager').then(m => ({ default: m.CustomerManager })));
const ExpensesModal = React.lazy(() => import('./components/ExpensesModal').then(m => ({ default: m.ExpensesModal })));
const AnalyticsModal = React.lazy(() => import('./components/AnalyticsModal').then(m => ({ default: m.AnalyticsModal })));

const ModalLoader = () => <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center"><div className="bg-gray-800 p-4 rounded-full border border-gray-700"><Loader2 className="animate-spin text-[#FA8072]" size={32} /></div></div>;

const WelcomeLoader: React.FC<{ onComplete: () => void; lastSessionTime: string | null }> = ({ onComplete, lastSessionTime }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(timer);
          setTimeout(onComplete, 500);
          return 100;
        }
        return prev + 4;
      });
    }, 80);

    return () => clearInterval(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-slate-950 z-[300] flex flex-col items-center justify-center p-6 text-center overflow-hidden font-['Cairo']">
      <div className="absolute inset-0 opacity-10">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(#FA8072_1px,transparent_1px)] [background-size:40px_40px]"></div>
      </div>
      <div className="relative z-10 flex flex-col items-center w-full max-w-md">
        <div className="mb-10 relative">
           <div className="w-24 h-24 bg-slate-900 border border-slate-800 rounded-3xl flex items-center justify-center mx-auto shadow-2xl relative overflow-hidden group">
              <div className="absolute inset-0 bg-gradient-to-tr from-[#FA8072]/20 to-transparent opacity-50"></div>
              <ShieldCheck className="text-[#FA8072] relative z-10" size={44} strokeWidth={1.5} />
           </div>
        </div>
        <div className="space-y-4 mb-14">
            <h1 className="text-5xl font-black text-white tracking-tighter animate-fade-up">مرحباً</h1>
            <div className="h-0.5 w-12 bg-[#FA8072] mx-auto rounded-full opacity-60"></div>
        </div>
        {lastSessionTime && (
          <div className="mb-10 flex items-center gap-3 px-6 py-3 bg-slate-900/50 border border-slate-800 rounded-2xl animate-fade-up">
            <Clock size={16} className="text-[#FA8072]" />
            <div className="flex flex-col items-start leading-none text-right">
              <span className="text-[10px] text-slate-500 font-bold uppercase mb-1">آخر نشاط مسجل</span>
              <span className="text-xs text-slate-300 font-black tabular-nums">{lastSessionTime}</span>
            </div>
          </div>
        )}
        <div className="w-full max-w-xs px-4">
            <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden border border-slate-800/50 p-0 mb-4">
              <div className="h-full bg-[#FA8072] rounded-full transition-all duration-300 ease-out" style={{ width: `${progress}%` }}></div>
            </div>
            <div className="flex justify-between items-center px-1">
                <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.3em]">System Authentication</span>
                <span className="text-[#FA8072] font-black tabular-nums text-[10px]">{progress}%</span>
            </div>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [previousSessionTime] = useState(() => localStorage.getItem('lastSessionTime'));
  const [isAuthenticated, setIsAuthenticated] = useState(() => sessionStorage.getItem('isAuth') === 'true');
  const [isInitializing, setIsInitializing] = useState(true); 
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date>(() => new Date());
  const [showLock, setShowLock] = useState<{ target: string; data?: any } | null>(null);
  const [lockPass, setLockPass] = useState('');
  const [lockError, setLockError] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [ordersCountSinceBackup, setOrdersCountSinceBackup] = useState(() => Number(localStorage.getItem('backupCounter') || 0));
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const [loginPassword, setLoginPassword] = useState(() => localStorage.getItem('loginPassword') || '2026');
  const [systemPassword, setSystemPassword] = useState(() => localStorage.getItem('systemPassword') || '@@A2026A@@');

  // State Management
  const [sales, setSales] = useState<SaleItem[]>(() => JSON.parse(localStorage.getItem('dailySales') || '[]'));
  const [purchaseInvoices, setPurchaseInvoices] = useState<PurchaseInvoice[]>(() => JSON.parse(localStorage.getItem('dailyPurchaseInvoices') || '[]'));
  const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>(() => JSON.parse(localStorage.getItem('dailySalaries') || '[]'));
  const [history, setHistory] = useState<ArchivedDay[]>(() => JSON.parse(localStorage.getItem('salesHistory') || '[]'));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('products') || '[]'));
  const [customers, setCustomers] = useState<Customer[]>(() => JSON.parse(localStorage.getItem('customers') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('suppliers') || '[]'));
  const [employees, setEmployees] = useState<Employee[]>(() => JSON.parse(localStorage.getItem('employees') || '[]'));
  const [inventory, setInventory] = useState<StockItem[]>(() => JSON.parse(localStorage.getItem('inventory') || '[]'));

  const [invoiceItems, setInvoiceItems] = useState<SaleItem[] | null>(null);
  const [modals, setModals] = useState({ products: false, customers: false, history: false, data: false, expenses: false, analytics: false });

  // Sync with LocalStorage
  useEffect(() => {
    localStorage.setItem('dailySales', JSON.stringify(sales));
    localStorage.setItem('dailyPurchaseInvoices', JSON.stringify(purchaseInvoices));
    localStorage.setItem('dailySalaries', JSON.stringify(salaryPayments));
    localStorage.setItem('salesHistory', JSON.stringify(history));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('customers', JSON.stringify(customers));
    localStorage.setItem('suppliers', JSON.stringify(suppliers));
    localStorage.setItem('employees', JSON.stringify(employees));
    localStorage.setItem('inventory', JSON.stringify(inventory));
    localStorage.setItem('loginPassword', loginPassword);
    localStorage.setItem('systemPassword', systemPassword);

    const now = new Date();
    localStorage.setItem('lastSessionTime', now.toLocaleString('en-US'));
    setLastSyncTime(now);
  }, [sales, purchaseInvoices, salaryPayments, history, products, customers, suppliers, employees, inventory, loginPassword, systemPassword]);

  const handleLogout = () => { sessionStorage.removeItem('isAuth'); setIsAuthenticated(false); };
  const handleOpenProtected = (target: string, data?: any) => { setShowLock({ target, data }); };
  const handleLoginSuccess = () => { sessionStorage.setItem('isAuth', 'true'); setIsAuthenticated(true); };
  const finalizeWelcome = () => setIsInitializing(false);

  const completeOrder = useCallback((items: any[], customerName?: string, customerId?: string, saleType: SaleType = 'retail') => {
    const orderId = Date.now().toString();
    const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    const todayDate = new Date().toLocaleDateString('en-US');
    const activeMax = sales.filter(s => s.date === todayDate).reduce((max, s) => Math.max(max, s.customerNumber), 0);
    const archivedToday = history.find(h => h.date === todayDate);
    const archivedMax = archivedToday ? archivedToday.items.reduce((max, s) => Math.max(max, s.customerNumber), 0) : 0;
    const nextCustomerNumber = Math.max(activeMax, archivedMax) + 1;

    const newItems: SaleItem[] = items.map(item => ({
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      orderId,
      customerNumber: nextCustomerNumber,
      customerName,
      customerId,
      saleType,
      time,
      date: todayDate
    }));

    setSales(prev => [...prev, ...newItems]);
    setInvoiceItems(newItems);
  }, [sales, history]);

  const handleArchiveDay = useCallback(() => {
      if (sales.length === 0 && purchaseInvoices.length === 0 && salaryPayments.length === 0) return alert('لا توجد بيانات للترحيل');
      const confirmed = window.confirm('ترحيل مبيعات ومصاريف اليوم للأرشيف؟');
      if (!confirmed) return;

      const dateStr = new Date().toLocaleDateString('en-US');
      setHistory(prev => [{
          id: `arch-${Date.now()}`,
          date: dateStr,
          timestamp: Date.now(),
          items: sales,
          purchaseInvoices: purchaseInvoices,
          salaryPayments: salaryPayments,
          totalRevenue: sales.reduce((s, i) => s + (i.price * i.quantity), 0),
          totalExpenses: purchaseInvoices.reduce((s, i) => s + i.totalAmount, 0) + salaryPayments.reduce((s, i) => s + i.amount, 0),
          totalItems: sales.length
      }, ...prev]);

      setSales([]);
      setPurchaseInvoices([]);
      setSalaryPayments([]);
      alert('تم الترحيل بنجاح');
  }, [sales, purchaseInvoices, salaryPayments]);

  const handleExportData = async () => {
    const backup = { sales, purchaseInvoices, salaryPayments, history, products, customers, suppliers, employees, inventory, loginPassword, systemPassword };
    const blob = new Blob([JSON.stringify(backup)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `cookies-bakery-backup-${new Date().toLocaleDateString()}.json`;
    link.click();
  };

  const handleImportData = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const data = JSON.parse(e.target?.result as string);
            if (data.sales) setSales(data.sales);
            if (data.inventory) setInventory(data.inventory);
            if (data.products) setProducts(data.products);
            if (data.history) setHistory(data.history);
            if (data.purchaseInvoices) setPurchaseInvoices(data.purchaseInvoices);
            if (data.salaryPayments) setSalaryPayments(data.salaryPayments);
            if (data.customers) setCustomers(data.customers);
            if (data.suppliers) setSuppliers(data.suppliers);
            if (data.employees) setEmployees(data.employees);
            if (data.loginPassword) setLoginPassword(data.loginPassword);
            if (data.systemPassword) setSystemPassword(data.systemPassword);
            alert('تم استيراد البيانات');
        } catch (err) { alert('خطأ في الملف'); }
    };
    reader.readAsText(file);
  };

  const verifyLock = () => {
    if (lockPass === systemPassword) {
      if (showLock?.target === 'full_reset') { localStorage.clear(); window.location.reload(); }
      else if (showLock) setModals(m => ({ ...m, [showLock.target]: true }));
      setShowLock(null); setLockPass(''); setLockError(false);
    } else setLockError(true);
  };

  if (isInitializing) return <WelcomeLoader onComplete={finalizeWelcome} lastSessionTime={previousSessionTime} />;
  if (!isAuthenticated) return <Login onLogin={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-gray-900 print:bg-white relative">
      <Header 
        onOpenHistory={() => handleOpenProtected('history')} 
        onOpenDataManagement={() => handleOpenProtected('data')} 
        onOpenExpenses={() => handleOpenProtected('expenses')}
        onOpenAnalytics={() => handleOpenProtected('analytics')}
        onLogout={handleLogout}
        isOnline={isOnline} 
        lastSyncTime={lastSyncTime} 
        onManualSync={() => { setIsSyncing(true); setTimeout(() => setIsSyncing(false), 800); }} 
        onQuickBackup={handleExportData} 
        isSyncing={isSyncing}
      />
      <main className="flex-grow container mx-auto px-4 py-6 max-w-5xl no-print">
        <Summary items={sales} onPreview={() => setInvoiceItems(sales)} systemPassword={systemPassword} />
        <POSInterface products={products} customers={customers} onCompleteOrder={completeOrder} onOpenProductManager={() => setModals(m => ({...m, products: true}))} onOpenCustomerManager={() => setModals(m => ({...m, customers: true}))} />
        <div className="mt-8">
            <SalesTable items={sales} onDeleteItem={(id: string) => setSales(s => s.filter(i => i.id !== id))} onDeleteOrder={(oid: string) => setSales(s => s.filter(i => i.orderId !== oid))} onPreviewInvoice={setInvoiceItems} onUpdateItemPrice={(id: string, p: number) => setSales(s => s.map(i => i.id === id ? {...i, price: p} : i))} />
        </div>
      </main>

      <Suspense fallback={<ModalLoader />}>
        {modals.analytics && <AnalyticsModal history={history} currentSales={sales} currentPurchases={purchaseInvoices} currentSalaries={salaryPayments} onClose={() => setModals(m => ({ ...m, analytics: false }))} />}
        {modals.expenses && <ExpensesModal 
          isOpen={modals.expenses} 
          onClose={() => setModals(m => ({...m, expenses: false}))} 
          currentPurchases={purchaseInvoices} 
          archivedHistory={history} 
          onAddInvoice={v => setPurchaseInvoices(p => [...p, v])} 
          onUpdateInvoice={v => setPurchaseInvoices(p => p.map(inv => inv.id === v.id ? v : inv))} 
          onDeleteInvoice={id => setPurchaseInvoices(p => p.filter(v => v.id !== id))} 
          suppliers={suppliers} 
          onAddSupplier={s => setSuppliers(p => [...p, {...s, id: Date.now().toString()}])} 
          onDeleteSupplier={id => setSuppliers(p => p.filter(s => s.id !== id))} 
          employees={employees}
          onAddEmployee={e => setEmployees(prev => [...prev, {...e, id: Date.now().toString()}])}
          onDeleteEmployee={id => setEmployees(prev => prev.filter(e => e.id !== id))}
          salaryPayments={salaryPayments}
          onAddSalaryPayment={p => setSalaryPayments(prev => [...prev, {...p, id: Date.now().toString()}])}
          onDeleteSalaryPayment={id => setSalaryPayments(prev => prev.filter(p => p.id !== id))}
          inventory={inventory} 
          setInventory={setInventory} 
        />}
        {modals.history && <HistoryModal history={history} currentSales={sales} onClose={() => setModals(m => ({...m, history: false}))} onPreviewInvoice={setInvoiceItems} onUpdateOrder={(dayId, orderId, items, name) => setHistory(prev => prev.map(day => day.id === dayId ? {...day, items: [...day.items.filter(it => it.orderId !== orderId), ...items]} : day))} onDeleteArchivedOrder={(dayId, orderId) => setHistory(prev => prev.map(day => day.id === dayId ? {...day, items: day.items.filter(it => it.orderId !== orderId)} : day))} onDeleteArchivedDay={id => setHistory(prev => prev.filter(d => d.id !== id))} />}
        {modals.products && <ProductManager isOpen={modals.products} onClose={() => setModals(m => ({...m, products: false}))} products={products} onAddProduct={p => setProducts(s => [...s, {...p, id: Date.now().toString()}])} onUpdateProduct={(id, up) => setProducts(p => p.map(it => it.id === id ? {...it, ...up} : it))} onDeleteProduct={id => setProducts(s => s.filter(p => p.id !== id))} />}
        {modals.customers && <CustomerManager isOpen={modals.customers} onClose={() => setModals(m => ({...m, customers: false}))} customers={customers} onAddCustomer={c => setCustomers(s => [...s, {...c, id: Date.now().toString()}])} onDeleteCustomer={id => setCustomers(s => s.filter(c => c.id !== id))} />}
        {modals.data && <DataManagementModal onClose={() => setModals(m => ({...m, data: false}))} onExport={handleExportData} onImport={handleImportData} onArchiveDay={handleArchiveDay} systemPassword={systemPassword} setSystemPassword={setSystemPassword} loginPassword={loginPassword} setLoginPassword={setLoginPassword} />}
        {invoiceItems && <InvoiceModal items={invoiceItems} onClose={() => setInvoiceItems(null)} />}
      </Suspense>

      {showLock && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 backdrop-blur-sm no-print">
          <div className="bg-gray-800 border border-gray-700 p-6 rounded-3xl w-full max-w-xs shadow-2xl animate-fade-up relative">
            <button onClick={() => { setShowLock(null); setLockPass(''); setLockError(false); }} className="absolute top-4 left-4 text-gray-500 hover:text-white transition-colors"><X size={20} /></button>
            <div className="text-center mb-6">
                <div className="w-12 h-12 bg-[#FA8072]/20 rounded-full flex items-center justify-center mx-auto mb-3"><Loader2 className="text-[#FA8072] animate-pulse" size={24} /></div>
                <h3 className="text-white font-black text-lg">تأكيد الإجراء</h3>
                <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest mt-1">أدخل كلمة المرور للمتابعة</p>
            </div>
            <input type="password" value={lockPass} onChange={e => setLockPass(e.target.value)} placeholder="رمز الدخول" className={`w-full bg-gray-900 border ${lockError ? 'border-red-500' : 'border-gray-700'} text-white p-4 rounded-2xl mb-4 text-center outline-none focus:border-[#FA8072] text-xl tracking-widest`} autoFocus onKeyDown={e => e.key === 'Enter' && verifyLock()} />
            {lockError && <p className="text-red-500 text-[10px] text-center mb-4 font-bold animate-pulse">رمز الدخول غير صحيح!</p>}
            <button onClick={verifyLock} className="w-full bg-gradient-to-r from-[#FA8072] to-orange-600 text-white py-4 rounded-2xl font-black text-sm shadow-lg active:scale-95 transition-all">تأكيد الإجراء</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, Suspense } from 'react';
import { Plus, Trash2, X, ShoppingCart, UserPlus, Printer, FileText, Store, Folder, CalendarDays, ArrowRight, Zap, ChevronDown, ChevronUp, Edit3, RotateCcw, Search, Package, ArrowDownLeft, AlertTriangle, Layers, Info, Users, Banknote } from 'lucide-react';
import { PurchaseInvoice, PurchaseItem, ArchivedDay, PaymentStatus, Supplier, StockItem, Employee, SalaryPayment } from '../types';

const PurchasePrintModal = React.lazy(() => import('./PurchasePrintModal').then(module => ({ default: module.PurchasePrintModal })));

interface ExpensesModalProps {
  currentPurchases: PurchaseInvoice[];
  archivedHistory: ArchivedDay[]; 
  onAddInvoice: (invoice: PurchaseInvoice) => void;
  onUpdateInvoice: (invoice: PurchaseInvoice) => void;
  onDeleteInvoice: (id: string) => void;
  isOpen: boolean;
  onClose: () => void;
  suppliers: Supplier[];
  onAddSupplier: (supplier: Omit<Supplier, 'id'>) => void;
  onDeleteSupplier: (id: string) => void;
  employees: Employee[];
  onAddEmployee: (employee: Omit<Employee, 'id'>) => void;
  onDeleteEmployee: (id: string) => void;
  salaryPayments: SalaryPayment[];
  onAddSalaryPayment: (payment: Omit<SalaryPayment, 'id'>) => void;
  onDeleteSalaryPayment: (id: string) => void;
  inventory: StockItem[];
  setInventory: React.Dispatch<React.SetStateAction<StockItem[]>>;
}

export const ExpensesModal: React.FC<ExpensesModalProps> = ({ 
  currentPurchases, archivedHistory, onAddInvoice, onUpdateInvoice, onDeleteInvoice, isOpen, onClose, 
  suppliers = [], onAddSupplier, onDeleteSupplier,
  employees = [], onAddEmployee, onDeleteEmployee,
  salaryPayments = [], onAddSalaryPayment, onDeleteSalaryPayment,
  inventory, setInventory
}) => {
  const [activeTab, setActiveTab] = useState<'new' | 'history' | 'suppliers' | 'inventory' | 'salaries'>('new');
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>('paid'); 
  const [itemInputs, setItemInputs] = useState({ name: '', quantity: '', unitPrice: '' });
  const [currentInvoiceItems, setCurrentInvoiceItems] = useState<PurchaseItem[]>([]);
  const [invoiceToPrint, setInvoiceToPrint] = useState<PurchaseInvoice | null>(null);
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);

  // Salaries & Employees State
  const [salaryForm, setSalaryForm] = useState({ employeeId: '', amount: '', notes: '' });
  const [empForm, setEmpForm] = useState({ name: '', position: '' });

  // Inventory Management State
  const [showAddStock, setShowAddStock] = useState(false);
  const [newStock, setNewStock] = useState({ name: '', unitType: 'kg' as 'kg'|'piece', minThreshold: 1 });
  const [consumeDialog, setConsumeDialog] = useState<{id: string, name: string, available: number} | null>(null);
  const [editQtyDialog, setEditQtyDialog] = useState<{id: string, name: string, current: number} | null>(null);
  const [actionQty, setActionQty] = useState('');

  const handleAddStockItem = () => {
    if (!newStock.name) return;
    const item: StockItem = {
        id: Date.now().toString(),
        name: newStock.name,
        currentQuantity: 0,
        unitType: newStock.unitType,
        minThreshold: newStock.minThreshold,
        lastUpdated: new Date().toLocaleDateString()
    };
    setInventory(prev => [...prev, item]);
    setNewStock({ name: '', unitType: 'kg', minThreshold: 1 });
    setShowAddStock(false);
  };

  const handleConsume = () => {
    if (!consumeDialog || !actionQty) return;
    const qtyToSubtract = parseFloat(actionQty);
    if (isNaN(qtyToSubtract)) return;

    setInventory(prev => prev.map(item => {
        if (item.id === consumeDialog.id) {
            const newQuantity = item.currentQuantity - qtyToSubtract;
            return { ...item, currentQuantity: newQuantity, lastUpdated: new Date().toLocaleDateString() };
        }
        return item;
    }));
    setConsumeDialog(null);
    setActionQty('');
  };

  const handleUpdateStockQty = () => {
    if (!editQtyDialog || !actionQty) return;
    const newQty = parseFloat(actionQty);
    if (isNaN(newQty)) return;

    setInventory(prev => prev.map(item => 
        item.id === editQtyDialog.id 
        ? { ...item, currentQuantity: newQty, lastUpdated: new Date().toLocaleDateString() }
        : item
    ));
    setEditQtyDialog(null);
    setActionQty('');
  };

  const addItemToInvoice = () => {
      if (!itemInputs.name || !itemInputs.quantity || !itemInputs.unitPrice) return;

      const existsInStock = inventory.some(i => i.name === itemInputs.name);
      if (!existsInStock) {
          alert('خطأ: هذه المادة غير معرفة في المستودع. يرجى تعريف المادة أولاً من تبويب المستودع قبل شرائها.');
          return;
      }

      const q = parseFloat(itemInputs.quantity); 
      const price = parseFloat(itemInputs.unitPrice);
      setCurrentInvoiceItems(prev => [...prev, { id: Date.now().toString(), name: itemInputs.name, quantity: q, cost: price, total: q * price }]);
      setItemInputs({ name: '', quantity: '', unitPrice: '' });
  };

  const handleSaveInvoice = () => {
      const supplier = suppliers.find(s => s.id === selectedSupplierId);
      if (!supplier || currentInvoiceItems.length === 0) return alert('يرجى تحديد مورد وإضافة مواد');

      const totalAmount = currentInvoiceItems.reduce((sum, item) => sum + item.total, 0);
      const invoiceData: PurchaseInvoice = { 
          id: editingInvoiceId || Date.now().toString(), 
          supplierName: supplier.name, 
          date: new Date().toLocaleDateString('ar-SY'), 
          timestamp: Date.now(), 
          items: currentInvoiceItems, 
          totalAmount, 
          paymentStatus 
      };

      setInventory(prev => {
          let updated = [...prev];
          currentInvoiceItems.forEach(purchaseItem => {
              const stockIdx = updated.findIndex(s => s.name === purchaseItem.name);
              if (stockIdx > -1) {
                  updated[stockIdx] = { 
                      ...updated[stockIdx], 
                      currentQuantity: updated[stockIdx].currentQuantity + purchaseItem.quantity,
                      lastUpdated: new Date().toLocaleDateString()
                  };
              }
          });
          return updated;
      });

      if (editingInvoiceId) onUpdateInvoice(invoiceData);
      else onAddInvoice(invoiceData);

      setSelectedSupplierId(''); setCurrentInvoiceItems([]); setEditingInvoiceId(null);
      setActiveTab('inventory');
  };

  const handleAddEmployee = () => {
    if (!empForm.name) return;
    onAddEmployee(empForm);
    setEmpForm({ name: '', position: '' });
  };

  const handleRecordSalary = () => {
    const employee = employees.find(e => e.id === salaryForm.employeeId);
    if (!employee || !salaryForm.amount) return alert('يرجى اختيار الموظف وتحديد المبلغ');

    onAddSalaryPayment({
        employeeId: employee.id,
        employeeName: employee.name,
        amount: parseFloat(salaryForm.amount),
        date: new Date().toLocaleDateString('ar-SY'),
        month: new Date().toLocaleString('ar-SY', { month: 'long' }),
        notes: salaryForm.notes
    });

    setSalaryForm({ employeeId: '', amount: '', notes: '' });
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-gray-800 rounded-[2.5rem] w-full max-w-2xl shadow-2xl border border-gray-700 flex flex-col h-[85vh] overflow-hidden">

        <div className="p-5 border-b border-gray-700 flex justify-between items-center bg-gray-900 shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-[#FA8072]/20 p-2.5 rounded-2xl"><Package className="text-[#FA8072]" size={24} /></div>
            <h3 className="font-black text-xl text-white">المخزون والمصاريف</h3>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-700 rounded-xl transition-all text-gray-400"><X size={24} /></button>
        </div>

        <div className="flex border-b border-gray-700 bg-gray-900/30 overflow-x-auto shrink-0">
            <button onClick={() => setActiveTab('inventory')} className={`flex-1 min-w-[80px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'inventory' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500'}`}>
                <Layers size={16} /> المستودع
            </button>
            <button onClick={() => setActiveTab('new')} className={`flex-1 min-w-[80px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'new' ? 'bg-[#FA8072] text-white shadow-lg' : 'text-gray-500'}`}>
                <ShoppingCart size={16} /> شراء جديد
            </button>
            <button onClick={() => setActiveTab('salaries')} className={`flex-1 min-w-[80px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'salaries' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-500'}`}>
                <Banknote size={16} /> الرواتب
            </button>
            <button onClick={() => setActiveTab('history')} className={`flex-1 min-w-[80px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'history' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500'}`}>
                <CalendarDays size={16} /> السجل
            </button>
            <button onClick={() => setActiveTab('suppliers')} className={`flex-1 min-w-[80px] py-4 text-[10px] font-black transition-all flex flex-col items-center gap-1 ${activeTab === 'suppliers' ? 'bg-gray-700 text-white' : 'text-gray-500'}`}>
                <Store size={16} /> الموردين
            </button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">

          {activeTab === 'inventory' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="flex justify-between items-center mb-4">
                      <h4 className="text-white font-black text-sm flex items-center gap-2"><Package size={16} className="text-indigo-400" /> جرد المستودع الحالي</h4>
                      <button onClick={() => setShowAddStock(!showAddStock)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-xl text-[10px] font-black flex items-center gap-2 transition-all">
                          {showAddStock ? <X size={14} /> : <Plus size={14} />} تعريف مادة خام
                      </button>
                  </div>

                  {showAddStock && (
                      <div className="bg-gray-900 border border-indigo-500/30 p-4 rounded-2xl mb-6 space-y-4 shadow-xl">
                          <p className="text-[10px] text-gray-400 font-bold mb-2">أضف المواد التي تشتريها وتريد جردها (مثل الطحين، السكر..)</p>
                          <div className="grid grid-cols-2 gap-3">
                              <input type="text" value={newStock.name} onChange={e => setNewStock({...newStock, name: e.target.value})} placeholder="اسم المادة الخام" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs" />
                              <select value={newStock.unitType} onChange={e => setNewStock({...newStock, unitType: e.target.value as any})} className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs">
                                  <option value="kg">كيلو (kg)</option>
                                  <option value="piece">قطعة (pcs)</option>
                              </select>
                          </div>
                          <button onClick={handleAddStockItem} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black text-xs">حفظ المادة في المستودع</button>
                      </div>
                  )}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      {inventory.map(item => (
                          <div key={item.id} className="bg-gray-900/60 p-5 rounded-3xl border border-gray-700 group hover:border-indigo-500/50 transition-all">
                              <div className="flex justify-between items-start mb-4">
                                  <div className="flex flex-col">
                                      <span className="text-white font-black text-sm">{item.name}</span>
                                      <span className="text-[9px] text-gray-500 font-bold">آخر تحديث: {item.lastUpdated}</span>
                                  </div>
                                  <button onClick={() => { setEditQtyDialog({id: item.id, name: item.name, current: item.currentQuantity}); setActionQty(item.currentQuantity.toString()); }} className="bg-gray-800 p-2 rounded-xl text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all"><Edit3 size={18} /></button>
                              </div>
                              <div className="flex items-center justify-between mb-4">
                                  <div className="flex items-baseline gap-1">
                                      <span className={`text-3xl font-black tabular-nums ${item.currentQuantity <= item.minThreshold ? 'text-red-500' : 'text-green-500'}`}>
                                          {item.currentQuantity}
                                      </span>
                                      <span className="text-[10px] text-gray-500 font-bold">{item.unitType === 'kg' ? 'كيلو' : 'قطعة'}</span>
                                  </div>
                                  <button onClick={() => { setConsumeDialog({id: item.id, name: item.name, available: item.currentQuantity}); setActionQty(''); }} className="bg-red-900/20 text-red-500 hover:bg-red-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black flex items-center gap-1.5 transition-all border border-red-500/20">
                                      <ArrowDownLeft size={14} /> استهلاك
                                  </button>
                              </div>
                              {item.currentQuantity <= item.minThreshold && (
                                  <div className="flex items-center gap-2 text-red-500 text-[9px] font-black animate-pulse bg-red-500/5 p-2 rounded-lg">
                                      <AlertTriangle size={12} /> {item.currentQuantity < 0 ? 'يوجد عجز في المادة!' : 'الكمية قاربت على النفاذ!'}
                                  </div>
                              )}
                          </div>
                      ))}
                      {inventory.length === 0 && (
                          <div className="col-span-full py-20 text-center text-gray-600 italic text-sm">لم يتم تعريف أي مواد خام في المستودع بعد.</div>
                      )}
                  </div>
              </div>
          )}

          {activeTab === 'new' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="bg-indigo-600/10 border border-indigo-600/20 p-4 rounded-2xl mb-4 flex items-start gap-3">
                      <Info size={20} className="text-indigo-400 shrink-0" />
                      <p className="text-[10px] text-indigo-200 font-bold leading-relaxed">تنبيه المشتريات: لن يقبل النظام إضافة أي مادة إلا إذا كانت معرفة في تبويب "المستودع" أولاً.</p>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black pr-1">تحديد المورد:</label>
                        <select value={selectedSupplierId} onChange={e => setSelectedSupplierId(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs font-bold outline-none focus:border-[#FA8072]">
                            <option value="">اختر مورد...</option>
                            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 font-black pr-1">حالة الدفع:</label>
                        <div className="flex bg-gray-900 p-1 rounded-xl border border-gray-700">
                            <button onClick={() => setPaymentStatus('paid')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'paid' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-500'}`}>نقدي</button>
                            <button onClick={() => setPaymentStatus('credit')} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${paymentStatus === 'credit' ? 'bg-orange-600 text-white shadow-lg' : 'text-gray-500'}`}>آجل</button>
                        </div>
                    </div>
                  </div>

                  <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                          <div className="relative group">
                              <input type="text" list="stock-options" value={itemInputs.name} onChange={e => setItemInputs({...itemInputs, name: e.target.value})} placeholder="اختر مادة من المستودع..." className="w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs font-bold focus:border-indigo-500 outline-none" />
                              <datalist id="stock-options">
                                  {inventory.map(i => <option key={i.id} value={i.name} />)}
                              </datalist>
                              <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-600"><Layers size={14} /></div>
                          </div>
                          <input type="number" value={itemInputs.quantity} onChange={e => setItemInputs({...itemInputs, quantity: e.target.value})} placeholder="الكمية المشتراة" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-center font-bold outline-none focus:border-green-500" />
                          <input type="number" value={itemInputs.unitPrice} onChange={e => setItemInputs({...itemInputs, unitPrice: e.target.value})} placeholder="سعر الشراء" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-center font-bold outline-none focus:border-green-500" />
                      </div>
                      <button onClick={addItemToInvoice} className="w-full bg-indigo-600 hover:bg-indigo-500 text-white py-3 rounded-xl font-black text-xs flex items-center justify-center gap-2 transition-all shadow-lg">
                          <Plus size={16} /> إضافة مادة للفاتورة
                      </button>
                  </div>

                  <div className="bg-gray-950/30 border border-gray-700 rounded-2xl overflow-hidden shadow-inner">
                      <table className="w-full text-xs text-right">
                          <thead className="bg-gray-900 text-gray-500 font-black uppercase text-[10px]"><tr><th className="p-4">الصنف</th><th className="p-4 text-center">الكمية</th><th className="p-4">الإجمالي</th><th className="p-4"></th></tr></thead>
                          <tbody className="divide-y divide-gray-800">
                              {currentInvoiceItems.map(item => (
                                  <tr key={item.id} className="hover:bg-gray-800/50">
                                      <td className="p-4 text-white font-black">{item.name}</td>
                                      <td className="p-4 text-center text-gray-400 font-bold tabular-nums">{item.quantity}</td>
                                      <td className="p-4 text-[#FA8072] font-black tabular-nums">{item.total.toLocaleString()}</td>
                                      <td className="p-4"><button onClick={() => setCurrentInvoiceItems(prev => prev.filter(i => i.id !== item.id))} className="text-gray-600 hover:text-red-500 p-1"><Trash2 size={16}/></button></td>
                                  </tr>
                              ))}
                              {currentInvoiceItems.length === 0 && <tr><td colSpan={4} className="p-16 text-center text-gray-700 italic text-sm">السلة فارغة، ابدأ باختيار مواد من المستودع</td></tr>}
                          </tbody>
                      </table>
                  </div>

                  <div className="flex items-center justify-between pt-6 border-t border-gray-700">
                      <div className="text-2xl font-black text-red-500 tabular-nums">
                          {currentInvoiceItems.reduce((s,i) => s + i.total, 0).toLocaleString()} <span className="text-[10px] text-gray-600 uppercase">ل.س</span>
                      </div>
                      <button onClick={handleSaveInvoice} className="bg-green-600 hover:bg-green-500 text-white px-8 py-4 rounded-2xl font-black text-sm flex items-center gap-3 shadow-xl transition-all active:scale-95">
                          <FileText size={20} /> حفظ الفاتورة وتحديث المستودع
                      </button>
                  </div>
              </div>
          )}

          {activeTab === 'salaries' && (
              <div className="space-y-6 animate-fade-up">
                  <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <div className="flex justify-between items-center mb-2">
                          <h4 className="text-white font-black text-sm flex items-center gap-2"><Users size={16} className="text-green-400" /> إدارة العمال والموظفين</h4>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          <input type="text" value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} placeholder="اسم العامل" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-2.5 text-white text-xs outline-none focus:border-green-500" />
                          <input type="text" value={empForm.position} onChange={e => setEmpForm({...empForm, position: e.target.value})} placeholder="المسمى الوظيفي" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-2.5 text-white text-xs outline-none focus:border-green-500" />
                      </div>
                      <button onClick={handleAddEmployee} className="w-full bg-green-600 hover:bg-green-500 text-white py-2.5 rounded-xl font-black text-xs transition-all shadow-lg">تعريف موظف جديد</button>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 max-h-[120px] overflow-y-auto custom-scrollbar pt-2">
                          {employees.map(e => (
                              <div key={e.id} className="bg-gray-950/40 p-3 rounded-xl border border-gray-800 flex justify-between items-center">
                                  <div className="flex flex-col">
                                      <span className="text-white font-black text-[11px]">{e.name}</span>
                                      <span className="text-gray-500 text-[9px] font-bold">{e.position || 'موظف'}</span>
                                  </div>
                                  <button onClick={() => onDeleteEmployee(e.id)} className="text-gray-700 hover:text-red-500 transition-colors"><Trash2 size={14}/></button>
                              </div>
                          ))}
                      </div>
                  </div>

                  <div className="bg-gray-900/40 p-5 rounded-2xl border border-gray-700 space-y-4">
                      <h4 className="text-white font-black text-sm flex items-center gap-2"><Banknote size={16} className="text-green-400" /> صرف راتب / سلفة</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          <select value={salaryForm.employeeId} onChange={e => setSalaryForm({...salaryForm, employeeId: e.target.value})} className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs outline-none focus:border-green-500 font-bold">
                              <option value="">اختر الموظف...</option>
                              {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                          </select>
                          <input type="number" value={salaryForm.amount} onChange={e => setSalaryForm({...salaryForm, amount: e.target.value})} placeholder="المبلغ المدفوع (ل.س)" className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs outline-none focus:border-green-500 font-black tabular-nums" />
                      </div>
                      <textarea value={salaryForm.notes} onChange={e => setSalaryForm({...salaryForm, notes: e.target.value})} placeholder="ملاحظات (مثلاً: راتب شهر يونيو، أو سلفة)" className="w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-white text-xs outline-none focus:border-green-500 resize-none h-20" />
                      <button onClick={handleRecordSalary} className="w-full bg-green-600 hover:bg-green-500 text-white py-4 rounded-xl font-black text-sm flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95">
                          <FileText size={20} /> تأكيد صرف المبلغ وتسجيله
                      </button>
                  </div>

                  <div className="space-y-3">
                      <h4 className="text-gray-500 font-black text-[10px] uppercase tracking-widest px-2">سجل دفعات اليوم</h4>
                      {salaryPayments.map(p => (
                          <div key={p.id} className="bg-gray-900/60 p-4 rounded-3xl border border-gray-700 flex justify-between items-center group transition-all">
                              <div className="flex items-center gap-4">
                                  <div className="bg-green-900/20 p-3 rounded-2xl text-green-400"><Banknote size={18} /></div>
                                  <div className="flex flex-col">
                                      <span className="text-white text-xs font-black">{p.employeeName}</span>
                                      <span className="text-[9px] text-gray-500 font-bold">{p.date} • {p.notes || 'لا توجد ملاحظات'}</span>
                                  </div>
                              </div>
                              <div className="flex items-center gap-3">
                                  <span className="text-green-500 font-black text-xs tabular-nums">{p.amount.toLocaleString()} ل.س</span>
